source:
Command -> {
  String:program
  List{T <- String}:args -> {}
}

run -> {
  Command:cmd
  -> exec{cmd -> cmd}!
}

runBackground -> {
  Command:cmd
  -> exec{cmd -> cmd}(!)
}

runThread -> {
  Command:cmd
  -> exec{cmd -> cmd}<!>
}

runGpu -> {
  Command:cmd
  -> exec{cmd -> cmd}|!|
}

runPar -> {
  Command:cmd
  -> exec{cmd -> cmd}[!]
}

pipeline -> {
  Command:a
  Command:b
  -> run{cmd -> a}(<!>)
}
